                {"speaker": "Child", "swissGerman": "Praktischi Sache wo mer im Betriib nöd cha lehre. Netzwärk uufsetze und Server konfiguriire.", "german": "Praktische Sachen die man im Betrieb nicht lernen kann. Netzwerke aufsetzen und Server konfigurieren.", "english": "Practical things you can't learn at the company. Setting up networks and configuring servers.", "spanish": "Cosas prácticas que no puedes aprender en la empresa. Configurar redes y servidores."},
                {"speaker": "You", "swissGerman": "Tönt spannend! Und wo isch das?", "german": "Klingt spannend! Und wo ist das?", "english": "Sounds exciting! And where is it?", "spanish": "¡Suena emocionante! ¿Y dónde está?"},
                {"speaker": "Child", "swissGerman": "Im Bildungszentrum z'Winterthur. Ich muess früecher ufstah.", "german": "Im Bildungszentrum in Winterthur. Ich muss früher aufstehen.", "english": "At the training center in Winterthur. I need to get up earlier.", "spanish": "En el centro de formación de Winterthur. Necesito levantarme más temprano."},
                {"speaker": "You", "swissGerman": "Denn stell der Wecker! Und nimm Zmittag mit, s'Ässe dört isch tüür.", "german": "Dann stell den Wecker! Und nimm Mittagessen mit, das Essen dort ist teuer.", "english": "Then set the alarm! And bring lunch, the food there is expensive.", "spanish": "¡Entonces pon el despertador! Y trae el almuerzo, la comida allí es cara."},
                {"speaker": "Child", "swissGerman": "Chani d'Unterlagen vom ÜK au im Betriib bruuche?", "german": "Kann ich die Unterlagen vom ÜK auch im Betrieb brauchen?", "english": "Can I also use the ÜK materials at the company?", "spanish": "¿También puedo usar los materiales del ÜK en la empresa?"},
