                {"speaker": "You", "swissGerman": "Gratuliere! S'erschte eigete Gäld. Was machsch du demit?", "german": "Gratuliere! Das erste eigene Geld. Was machst du damit?", "english": "Congrats! Your first own money. What will you do with it?", "spanish": "¡Enhorabuena! Tu primer dinero propio. ¿Qué vas a hacer con él?"},
                {"speaker": "Child", "swissGerman": "Ich wett en nöie Laptop chaufe. Für d'Schuel und privat.", "german": "Ich würde einen neuen Laptop kaufen. Für die Schule und privat.", "english": "I want to buy a new laptop. For school and private.", "spanish": "Quiero comprar un portátil nuevo. Para la escuela y uso personal."},
                {"speaker": "You", "swissGerman": "Gueti Idee! Aber spare au chli. Leg mindeschtens 200 Franke uf d'Siite.", "german": "Gute Idee! Aber spare auch etwas. Leg mindestens 200 Franken auf die Seite.", "english": "Good idea! But save some too. Put at least 200 francs aside.", "spanish": "¡Buena idea! Pero ahorra también. Pon al menos 200 francos a un lado."},
                {"speaker": "Child", "swissGerman": "Ja, ich mach e Sparkonto. De Papi hät mir s'e-Banking iigrichtet.", "german": "Ja, ich mache ein Sparkonto. Papa hat mir das e-Banking eingerichtet.", "english": "Yes, I'll make a savings account. Dad set up e-banking for me.", "spanish": "Sí, abriré una cuenta de ahorro. Papá me configuró la banca electrónica."},
                {"speaker": "You", "swissGerman": "Super! Und vergiss nöd, ab em zwöite Lehrjahr zahlsch du Sozialversicherig.", "german": "Super! Und vergiss nicht, ab dem zweiten Lehrjahr zahlst du Sozialversicherung.", "english": "Great! And don't forget, from the second apprenticeship year you pay social insurance.", "spanish": "¡Genial! Y no olvides, a partir del segundo año de aprendizaje pagas seguridad social."},
                {"speaker": "Child", "swissGerman": "Wie viel isch das öppe im Monet?", "german": "Wie viel ist das ungefähr im Monat?", "english": "About how much is that per month?", "spanish": "¿Aproximadamente cuánto es eso al mes?"},
